12	const PROCESSING_FEE = 5;
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	const FIRST_INSURANCE_MULTIPLIER = 1.1;
21	
22	const COMPONENT_TYPES = ["rune"];
23	const COMPONENT_BASE_PREMIUM = 25;
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PREMIUM = 60;
26	
27	const isComponent = (item: Item): boolean =>
28	  COMPONENT_TYPES.includes(item.type);
29	
30	// Base premium for `count` alike components: a block premium applies only for
31	// exactly one block's worth (3) of components; otherwise each is priced individually.
32	const componentBasePremium = (count: number): number => {
33	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
34	  return count * COMPONENT_BASE_PREMIUM;
35	};
36	
37	// Round up in MHPCO's favour, guarding against floating-point noise
38	// (e.g. 197.50000000001 should still round to 198, not 199).
39	const roundUpInMHPCOFavor = (amount: number): number =>
40	  Math.ceil(Number(amount.toFixed(6)));
41	
42	export const quote = (
43	  items: Item[],
44	  customer: Customer,
45	  contractIndex: number,
46	): number => {
47	  const mainItems = items.filter((item) => !isComponent(item));
48	  const componentCount = items.length - mainItems.length;
49	
50	  const mainBase = mainItems.reduce(
51	    (sum, item) => sum + BASE_PREMIUMS[item.type] * FIRST_INSURANCE_MULTIPLIER,
52	    0,
53	  );
54	  const componentBase =
55	    componentBasePremium(componentCount) * FIRST_INSURANCE_MULTIPLIER;
56	
57	  return roundUpInMHPCOFavor(mainBase + componentBase + PROCESSING_FEE);
58	};
59	
60	export const claim = (): number => {
61	  return undefined as unknown as number;
62	};
