// Base premiums for main (non-component) items. Components such as runes are
// priced separately via componentBasePremium and never read from this table.
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};
